export async function reserveSeat(
  seatId: string,
  userId: string,
  db: Database
): Promise<Reservation> {
  // AC4: seat must exist
  const seat = await db.findSeat(seatId);
  if (seat === null) {
    throw new ReservationError("SEAT_NOT_FOUND", `Seat ${seatId} does not exist`);
  }

  // AC2: fast-path — seat already reserved at read time
  if (seat.status !== "available") {
    throw new ReservationError("SEAT_ALREADY_RESERVED", `Seat ${seatId} is already reserved`);
  }

  // AC1 + AC3: atomic update with optimistic lock
  // Only succeeds if status is STILL 'available' in the DB right now
  const updated = await db.updateSeatStatus(seatId, "reserved", userId, "available");

  if (!updated) {
    // Another concurrent caller won the race between our read and this write
    throw new ReservationError("SEAT_ALREADY_RESERVED", `Seat ${seatId} was reserved by another request`);
  }

  return { seatId, userId, reservedAt: new Date() };
}
```

### Key design decisions

| Decision | Rationale |
|---|---|
| **`ReservationError` class with `.code`** | Strongly-typed error codes — callers pattern-match on `.code`, not `.message` strings |
| **Two-phase check** | Fast-path `status !== "available"` short-circuits before hitting `updateSeatStatus`; optimistic lock handles the race that slips through |
| **Optimistic locking via `expectedCurrentStatus`** | No distributed mutex needed — the DB's atomic CAS (`UPDATE … WHERE status = 'available'`) is the single serialization point |

